// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(
    localStorage.getItem("user")
  );

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  useEffect(() => {
    getRequests();
  }, []);

  // ======================
  // GET REQUESTS
  // ======================
  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // ======================
  // SEARCH WORKERS
  // ======================
  const searchWorkers = async (workType) => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter((worker) =>
        worker.skills.includes(workType)
      );

      setWorkers(filtered);

    } catch (err) {
      console.log(err);
    }
  };

  // ======================
  // SEND REQUEST
  // ======================
  const sendRequest = async () => {

    if (
      !form.workType ||
      !form.labourId ||
      !form.location ||
      !form.date
    ) {
      return alert("Please fill all fields");
    }

    try {

      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerName: user.name,
          customerId: user._id,
          labourId: form.labourId,
          labourName: form.labourName,
          workType: form.workType,
          location: form.location,
          date: form.date,
          timings: ["9AM - 12PM"]
        }
      );

      alert("Request Sent Successfully");

      setForm({
        workType: "",
        labourId: "",
        labourName: "",
        location: "",
        date: ""
      });

      setWorkers([]);
      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  // ======================
  // CUSTOMER DECISION
  // ======================
  const customerDecision = async (id, decision) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/customer-decision/${id}`,
        { decision }
      );

      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  // ======================
  // FEEDBACK
  // ======================
  const submitFeedback = async (id, rating, comment) => {
    if (!rating || !comment) {
      return alert("Please enter rating and review");
    }

    try {
      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );

      alert("Feedback Submitted");
      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* LEFT PANEL */}
        <div style={styles.card}>

          <h2 style={styles.heading}>Hire Workers</h2>

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {
              setForm({
                ...form,
                workType: e.target.value
              });
              searchWorkers(e.target.value);
            }}
          >
            <option value="">Select Work</option>
            {jobs.map((job, i) => (
              <option key={i} value={job}>
                {job}
              </option>
            ))}
          </select>

          {workers.length > 0 && (
            <select
              style={styles.input}
              onChange={(e) => {

                const worker = workers.find(
                  (w) => w._id === e.target.value
                );

                setForm({
                  ...form,
                  labourId: worker._id,
                  labourName: worker.name
                });
              }}
            >
              <option>Select Worker</option>

              {workers.map((w) => (
                <option key={w._id} value={w._id}>
                  {w.name} - {w.city}
                </option>
              ))}
            </select>
          )}

          <input
            style={styles.input}
            placeholder="Enter Location"
            value={form.location}
            onChange={(e) =>
              setForm({
                ...form,
                location: e.target.value
              })
            }
          />

          <input
            type="date"
            style={styles.input}
            value={form.date}
            onChange={(e) =>
              setForm({
                ...form,
                date: e.target.value
              })
            }
          />

          <button
            style={styles.button}
            onClick={sendRequest}
          >
            Send Request
          </button>

        </div>

        {/* RIGHT PANEL */}
        <div style={styles.card}>

          <h2 style={styles.heading}>My Requests</h2>

          {requests.length === 0 && (
            <p style={{ color: "#9ca3af" }}>
              No Requests Found
            </p>
          )}

          {requests.map((req) => (
            <div
              key={req._id}
              style={styles.requestBox}
            >

              <h3 style={{ color: "#f97316" }}>
                {req.labourName}
              </h3>

              <p>Work: {req.workType}</p>
              <p>Location: {req.location}</p>
              <p>Date: {req.date}</p>

              <p>Status: {req.status}</p>
              <p>Labour Response: {req.labourResponse}</p>
              <p>Price: ₹{req.labourPrice}</p>
              <p>Decision: {req.customerDecision}</p>

              {/* ACCEPT / REJECT */}
              {req.labourResponse === "Accepted" &&
                req.customerDecision === "Waiting" && (

                  <div style={styles.row}>

                    <button
                      style={styles.acceptBtn}
                      onClick={() =>
                        customerDecision(req._id, "Accepted")
                      }
                    >
                      Accept
                    </button>

                    <button
                      style={styles.rejectBtn}
                      onClick={() =>
                        customerDecision(req._id, "Rejected")
                      }
                    >
                      Reject
                    </button>

                  </div>
                )}

              {/* FEEDBACK */}
              {req.customerDecision === "Accepted" && (
                <div>

                  <input
                    type="number"
                    min="1"
                    max="5"
                    placeholder="Rating"
                    style={styles.input}
                    onChange={(e) =>
                      setRequests(
                        requests.map((item) =>
                          item._id === req._id
                            ? {
                                ...item,
                                tempRating: e.target.value
                              }
                            : item
                        )
                      )
                    }
                  />

                  <textarea
                    placeholder="Write review"
                    style={styles.textarea}
                    onChange={(e) =>
                      setRequests(
                        requests.map((item) =>
                          item._id === req._id
                            ? {
                                ...item,
                                tempComment: e.target.value
                              }
                            : item
                        )
                      )
                    }
                  />

                  <button
                    style={styles.feedbackBtn}
                    onClick={() =>
                      submitFeedback(
                        req._id,
                        req.tempRating,
                        req.tempComment
                      )
                    }
                  >
                    Submit Rating
                  </button>

                </div>
              )}

            </div>
          ))}

        </div>

      </div>

    </div>
  );
}

/* ======================
   MODERN DARK ORANGE UI
====================== */

const styles = {

  page: {
    minHeight: "100vh",
    background: "#0b0f19",
    color: "white"
  },

  container: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px",
    padding: "20px"
  },

  card: {
    background: "#111827",
    border: "1px solid #f97316",
    borderRadius: "16px",
    padding: "20px"
  },

  heading: {
    color: "#f97316",
    marginBottom: "15px"
  },

  input: {
    width: "100%",
    padding: "12px",
    marginBottom: "12px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white"
  },

  button: {
    width: "100%",
    padding: "12px",
    background: "#f97316",
    border: "none",
    borderRadius: "10px",
    color: "white",
    fontWeight: "bold",
    cursor: "pointer"
  },

  requestBox: {
    border: "1px solid #374151",
    borderRadius: "12px",
    padding: "15px",
    marginBottom: "15px",
    background: "#1f2937"
  },

  row: {
    display: "flex",
    gap: "10px",
    marginTop: "10px"
  },

  acceptBtn: {
    flex: 1,
    background: "green",
    border: "none",
    padding: "8px",
    borderRadius: "8px",
    color: "white"
  },

  rejectBtn: {
    flex: 1,
    background: "red",
    border: "none",
    padding: "8px",
    borderRadius: "8px"
  },

  textarea: {
    width: "100%",
    height: "70px",
    marginTop: "10px",
    padding: "10px",
    borderRadius: "10px",
    background: "#1f2937",
    border: "1px solid #f97316",
    color: "white"
  },

  feedbackBtn: {
    width: "100%",
    marginTop: "10px",
    padding: "10px",
    background: "#111827",
    border: "1px solid #f97316",
    color: "white",
    borderRadius: "10px"
  }
};
